package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringReader;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testIsEscapeCharacterSet() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        boolean result = csvFormat.isEscapeCharacterSet();

        // Then
        assertFalse(result);
    }

    @Test
    public void testIsEscapeCharacterSetWithEscapeCharacter() {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, '\\', false, true, "\r\n",
            null, null, null, false, false, false, false, false);

        // When
        boolean result = csvFormat.isEscapeCharacterSet();

        // Then
        assertTrue(result);
    }

    @Test
    public void testIsEscapeCharacterSetWithEscapeCharacterNull() {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
            null, null, null, false, false, false, false, false);

        // When
        boolean result = csvFormat.isEscapeCharacterSet();

        // Then
        assertFalse(result);
    }
}
